\displaystyle{\begin{aligned}
   {\frac{\frac{3}{y}}{12+\frac{3x}{2}}} 
      \amp = {\frac{\frac{3}{y}}{12+\frac{3x}{2}}} \cdot \frac{{2y}}{{2y}} \\
      \amp = \frac{ \frac{3}{y} \cdot 2 y}{(12+\frac{3 x}{2}) \cdot 2 y} \\
      \amp = \frac{3 \cdot 2}{12 \cdot 2 y + \frac{3 x}{2} \cdot 2 y} \\
      \amp = \frac{6}{24 y + 3 y x} \\
      \amp = \frac{6}{3 y (8 + x)} \\
      \amp = {\frac{2}{y\mathopen{}\left(x+8\right)}\hbox{ or }\frac{2}{yx+8y}}
\end{aligned}
    }
